 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import {
 4	  DescriptionList,
 5	  DescriptionListDescription,
 6	  DescriptionListGroup,
 7	  DescriptionListTerm,
 8	} from '@patternfly/react-core';
 9	import { PipelineKind, TaskKind } from '../../../types';
10	
11	export interface WorkspaceDefinitionListProps {
12	  obj: TaskKind | PipelineKind;
13	}
14	
15	const WorkspaceDefinitionList: React.FC<WorkspaceDefinitionListProps> = ({
16	  obj,
17	}) => {
18	  const { t } = useTranslation('plugin__pipelines-console-plugin');
19	  if (!obj?.spec?.workspaces || obj?.spec?.workspaces?.length === 0)
20	    return null;
21	
22	  return (
23	    <DescriptionList data-test-id="workspace-definition-section">
24	      <DescriptionListGroup>
25	        <DescriptionListTerm>{t('Workspaces')}</DescriptionListTerm>
26	        <DescriptionListDescription>
27	          {obj.spec.workspaces.map((workspace) => (
28	            <div
29	              key={workspace.name}
30	              data-test-id={`workspace-definition${
31	                workspace?.optional ? '-optional' : ''
32	              }`}
33	            >
34	              {workspace?.optional
35	                ? `${workspace.name} (${t('optional')})`
36	                : `${workspace.name}`}
37	            </div>
38	          ))}
39	        </DescriptionListDescription>
40	      </DescriptionListGroup>
41	    </DescriptionList>
42	  );
43	};
44	
45	export default WorkspaceDefinitionList;

